query:
-- Check GBA Consulting Engineers services not being billed
SELECT externalId, planName, serviceType, provider, monthlyCost FROM services
WHERE customerExternalId = 'C0101' AND monthlyCost > 0 AND monthlyRevenue = 0;

-- Check if GBA has any Xero billing items
SELECT contactName, description, lineAmount FROM billing_items
WHERE contactName LIKE '%GBA%' LIMIT 10;

-- Check Middlemount Coal services
SELECT externalId, planName, serviceType, provider, monthlyCost FROM services
WHERE customerExternalId = 'C0161' AND monthlyCost > 0 AND monthlyRevenue = 0;

-- Check Osprey Body Corporate
SELECT externalId, planName, serviceType, provider, monthlyCost FROM services
WHERE customerExternalId = 'C0038' AND monthlyCost > 0 AND monthlyRevenue = 0;

-- Check Salter Brothers entities
SELECT s.externalId, s.planName, s.provider, s.monthlyCost, c.name as customer
FROM services s JOIN customers c ON s.customerExternalId = c.externalId
WHERE c.name LIKE '%Salter%' AND s.monthlyCost > 0 AND s.monthlyRevenue = 0;

